import{_ as t,o as n,c as r,a2 as i}from"./chunks/framework.DTa47_fH.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"SWAO","text":"Sovereign Workload Assessment and Onboarding","tagline":"Audit-konforme Cloud-Workload-Bewertungen in einem einzigen Befehl. Keine Telemetrie. Kein Call-home. Ihre Daten bleiben auf Ihrem Rechner.","actions":[{"theme":"brand","text":"Schnellstart (5 Min.)","link":"/de/quick-start"},{"theme":"alt","text":"Funktionen & Editionen","link":"/de/features"},{"theme":"alt","text":"Wie es funktioniert","link":"/de/how-it-works"}]},"features":[{"title":"Fünf Bewertungstypen","details":"Anwendung, Landing Zone, Audit, LLM-Benchmarking und Hybrid. Führen Sie die vollständige Pipeline aus oder fokussieren Sie sich auf eine bestimmte Fläche."},{"title":"Eigenes LLM mitbringen","details":"Anthropic Claude, OpenAI, Ollama oder ein deterministischer Stub für den Offline-Betrieb. LLM-Zugriff ist in jeder Edition enthalten."},{"title":"Audit-konforme Nachvollziehbarkeit","details":"Jedes Signal enthält Ergebnis, Ableitung, Bewerteridentität, Falsch-Positiv-Betrachtung und Zeitstempel. Vertretbar gegenüber externen Prüfern."},{"title":"HTML-Veröffentlichung","details":"Eine eigenständige HTML-Datei mit Führungs-, Fach-, Compliance- und Prüferansichten. Funktioniert offline, in luftgespalteten Umgebungen und per E-Mail."},{"title":"PowerBI-Dashboards","details":"Vorgefertigte Vorlagen für Einzel- und Portfolio-Bewertungen. Sternschema-CSV-Export funktioniert mit jedem BI-Tool."},{"title":"MCP-Integration","details":"Stellen Sie Claude AI Fragen zu Ihren Bewertungsergebnissen in natürlicher Sprache über das Model Context Protocol."}]},"headers":[],"relativePath":"de/index.md","filePath":"de/index.md"}'),a={name:"de/index.md"};function d(s,e,l,o,u,h){return n(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="was-ist-swao" tabindex="-1">Was ist SWAO? <a class="header-anchor" href="#was-ist-swao" aria-label="Permalink to &quot;Was ist SWAO?&quot;">​</a></h2><p>SWAO analysiert Cloud-Anwendungen und -Infrastruktur und erstellt einen audit-konformen Bewertungsbericht. Es kombiniert statische Code-Analyse, LLM-gestützte Compliance-Bewertung und Kontexteinlese aus Ihrem CMDB und Betriebsdokumenten -- und liefert eine vollständige Rückverfolgungskette von Quellevidenz bis zum Compliance-Urteil.</p><p><strong>Nur Dateien auf der Festplatte.</strong> Keine Telemetrie, kein gehosteter Endpunkt, kein Call-home. Ihr Quellcode und Ihre Bewertungsdaten verlassen Ihren Rechner nicht. Bringen Sie Ihren eigenen LLM-Anbieter mit.</p><hr><h2 id="bewertungstypen" tabindex="-1">Bewertungstypen <a class="header-anchor" href="#bewertungstypen" aria-label="Permalink to &quot;Bewertungstypen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Typ</th><th>Status</th><th>Was Sie erhalten</th></tr></thead><tbody><tr><td>Anwendungsbewertung</td><td>Verfügbar</td><td>Vollständige Pipeline: Inventar, SBOM, Datenklassifizierung, Compliance, 7R-Synthese</td></tr><tr><td>Landing-Zone-Bewertung</td><td>Verfügbar</td><td>Cloud-Infrastruktur-Fit/Gap-Bericht gegen Souveränitätsanforderungen</td></tr><tr><td>Audit-Bewertung</td><td>Demnächst</td><td>Menschgeführte Checkliste und Evidenz mit deterministischem Compliance-Urteil</td></tr><tr><td>LLM-Bewertung</td><td>Demnächst</td><td>Paralleles Souveränitäts-Benchmarking über mehrere LLM-Anbieter</td></tr><tr><td>Hybrid-Bewertung</td><td>Demnächst</td><td>Kombinierte Quellanalyse und Consultant-Audit-Evidenz</td></tr></tbody></table><hr><h2 id="fragen-und-lizenzanfragen" tabindex="-1">Fragen und Lizenzanfragen <a class="header-anchor" href="#fragen-und-lizenzanfragen" aria-label="Permalink to &quot;Fragen und Lizenzanfragen&quot;">​</a></h2><p>Starten Sie eine <a href="https://github.com/Accenture/SWAO/discussions" target="_blank" rel="noreferrer">GitHub-Diskussion</a> oder <a href="https://github.com/Accenture/SWAO/issues" target="_blank" rel="noreferrer">eröffnen Sie ein Issue</a>.</p>',9)])])}const f=t(a,[["render",d]]);export{c as __pageData,f as default};
